const body = $json.body || {};
const ticketId = 'GX-' + Math.floor(Date.now() / 1000).toString(36).toUpperCase();

const ticket = {
  ticketId,
  clientName: body.clientName || body.name || 'Cliente',
  clientEmail: body.clientEmail || body.email || '',
  clientPhone: body.clientPhone || body.phone || '',
  issue: body.issue || body.message || body.summary || 'Sem descricao',
  category: body.category || 'general',
  priority: body.priority || 'normal',
  chatHistory: body.chatHistory || body.history || 'Sem historico',
  language: body.language || 'pt',
  receivedAt: new Date().toISOString()
};

// Build AI prompt for categorization
ticket.aiPrompt = 'Classifique e faca briefing deste ticket de suporte em portugues:\n\nProblema: ' + ticket.issue + '\nHistorico: ' + ticket.chatHistory + '\n\nResponda em JSON:\n{\n  "categoria": "urgent|site|ghl|billing|general",\n  "prioridade": "alta|media|baixa",\n  "resumo": "1-2 frases do problema",\n  "acao_sugerida": "o que a equipe deve fazer"\n}';

return [{ json: ticket }];
